public class Sieve {
    public static void main(String[] args) {
        int n = 20;
        boolean[] composite = new boolean[n + 1];
        for (int i = 2; i * i <= n; i++) {
            if (!composite[i]) {
                for (int j = i * i; j <= n; j += i) {
                    composite[j] = true;
                }
            }
        }
        int count = 0;
        for (int i = 2; i <= n; i++) {
            if (!composite[i]) count++;
        }
        System.out.println(count);
    }
}
